#include <cstdlib>
#include <cstring>
#include <fstream>
#include <iomanip>
#include <iostream>
#include <string>
#include <cmath>
#include <omp.h>

#define MAX_THREADS_PER_BLOCK 256

struct Node {
    int starting;
    int no_of_edges;
};

template<typename datatype>
void compare_results(const datatype *cpu_results, const datatype *gpu_results, const int size){
    char passed = true; 
    for (int i=0; i<size; i++){
      if (cpu_results[i]!=gpu_results[i]){
         passed = false; 
      }
    }
    if (passed){
        std::cout << "--cambine:passed:-)" << std::endl;
    }
    else{
        std::cout << "--cambine: failed:-(" << std::endl;
    }
    return ;
}

void run_bfs_cpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size, 
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask, 
                 char *h_graph_visited, int *h_cost_ref)
{
    char stop;
    int k = 0;
    do {
        stop=false;
#pragma omp parallel for schedule(static)
        for(int tid = 0; tid < no_of_nodes; tid++ ) {
            if (h_graph_mask[tid] == true) {
                h_graph_mask[tid]=false;
                int start = h_graph_nodes[tid].starting;
                int end = start + h_graph_nodes[tid].no_of_edges;
                for(int i=start; i<end; i++) {
                    int id = h_graph_edges[i];	
                    if(!h_graph_visited[id]) {	
                        h_cost_ref[id]=h_cost_ref[tid]+1;
                        h_updating_graph_mask[id]=true;
                    }
                }
            }
        }

        stop = false;
#pragma omp parallel for schedule(static)
        for(int tid=0; tid< no_of_nodes ; tid++ ) {
            if (h_updating_graph_mask[tid] == true) {
                h_graph_mask[tid]=true;
                h_graph_visited[tid]=true;
                stop=true;
                h_updating_graph_mask[tid]=false;
            }
        }
    } while(stop);
}

void run_bfs_omp(int no_of_nodes, Node *h_graph_nodes, int edge_list_size, 
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask, 
                 char *h_graph_visited, int *h_cost)
{
    char stop;
    do {
        stop = false;
#pragma omp parallel for schedule(static)
        for(int tid = 0; tid < no_of_nodes; tid++) {
            if (h_graph_mask[tid]) {
                h_graph_mask[tid] = false;
                int start = h_graph_nodes[tid].starting;
                int end = start + h_graph_nodes[tid].no_of_edges;
                for(int i = start; i < end; i++) {
                    int id = h_graph_edges[i];
                    if(!h_graph_visited[id]) {
                        h_cost[id] = h_cost[tid] + 1;
                        h_updating_graph_mask[id] = true;
                    }
                }
            }
        }

        stop = false;
#pragma omp parallel for schedule(static)
        for(int tid = 0; tid < no_of_nodes; tid++) {
            if (h_updating_graph_mask[tid]) {
                h_graph_mask[tid] = true;
                h_graph_visited[tid] = true;
                stop = true;
                h_updating_graph_mask[tid] = false;
            }
        }
    } while(stop);
}

void Usage(int argc, char**argv)
{
    fprintf(stderr,"Usage: %s <input_file> [-p platform] [-d device] [-t gpu(0)/cpu(1)]\n", argv[0]);
}

int main(int argc, char * argv[])
{
    int no_of_nodes;
    int edge_list_size;
    FILE *fp;
    Node* h_graph_nodes = nullptr;
    char *h_graph_mask = nullptr, *h_updating_graph_mask = nullptr, *h_graph_visited = nullptr;
    try {
        char *input_f;
        if(argc < 2) {
            Usage(argc, argv);
            exit(0);
        }

        input_f = argv[1];
        printf("Reading File\n");

        fp = fopen(input_f,"r");
        if(!fp) {
            printf("Error Reading graph file\n");
            return 0;
        }

        int source = 0;

        fscanf(fp,"%d",&no_of_nodes);

        int num_of_blocks = 1;
        int num_of_threads_per_block = no_of_nodes;

        if(no_of_nodes>MAX_THREADS_PER_BLOCK) {
            num_of_blocks = (int)ceil(no_of_nodes/(double)MAX_THREADS_PER_BLOCK);
            num_of_threads_per_block = MAX_THREADS_PER_BLOCK;
        }

        h_graph_nodes = (Node*) malloc(sizeof(Node)*no_of_nodes);
        h_graph_mask = (char*) malloc(sizeof(char)*no_of_nodes);
        h_updating_graph_mask = (char*) malloc(sizeof(char)*no_of_nodes);
        h_graph_visited = (char*) malloc(sizeof(char)*no_of_nodes);

        int start, edgeno;

        for(int i = 0; i < no_of_nodes; i++) {
            fscanf(fp,"%d %d",&start,&edgeno);
            h_graph_nodes[i].starting = start;
            h_graph_nodes[i].no_of_edges = edgeno;
            h_graph_mask[i]=false;
            h_updating_graph_mask[i]=false;
            h_graph_visited[i]=false;
        }

        fscanf(fp,"%d",&source);
        source=0;

        h_graph_mask[source]=true;
        h_graph_visited[source]=true;
        fscanf(fp,"%d",&edge_list_size);
        int id,cost;
        int* h_graph_edges = (int*) malloc(sizeof(int)*edge_list_size);
        for(int i=0; i < edge_list_size ; i++) {
            fscanf(fp,"%d",&id);
            fscanf(fp,"%d",&cost);
            h_graph_edges[i] = id;
        }

        if(fp)
            fclose(fp);

        int	*h_cost = (int*) malloc(sizeof(int)*no_of_nodes);
        int *h_cost_ref = (int*)malloc(sizeof(int)*no_of_nodes);
        for(int i=0; i<no_of_nodes; i++) {
            h_cost[i]=-1;
            h_cost_ref[i] = -1;
        }
        h_cost[source]=0;
        h_cost_ref[source]=0;

        // Run BFS with OpenMP parallelization (replacing GPU)
        run_bfs_omp(no_of_nodes,h_graph_nodes,edge_list_size,h_graph_edges, h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost);

        for(int i = 0; i < no_of_nodes; i++) {
            h_graph_mask[i]=false;
            h_updating_graph_mask[i]=false;
            h_graph_visited[i]=false;
        }

        source=0;
        h_graph_mask[source]=true;
        h_graph_visited[source]=true;
        run_bfs_cpu(no_of_nodes,h_graph_nodes,edge_list_size,h_graph_edges, h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost_ref);

        compare_results<int>(h_cost_ref, h_cost, no_of_nodes);

        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
        free(h_graph_edges);
        free(h_cost);
        free(h_cost_ref);

    } catch(std::string msg) {
        std::cout<<"--cambine: exception in main ->"<<msg<<std::endl;

        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
    }

    return 0;
}
